                                // processFormulas + render happen below via shared tail — jump by not returning early after hydrate copy\r\n                            } else {\r\n                                var logisticsEl = document.getElementById('pa-view-logistics');\r\n                                if (logisticsEl) {\r\n                                    logisticsEl.innerHTML = '<div style=\"padding:20px; text-align:center; color:#888;\">Syncing live prep…</div>';\r\n                                }\r\n                                if (typeof window.evalOperationButtons === 'function') window.evalOperationButtons();\r\n                                return;\r\n                            }\r\n                        } else {\r\n                            var logisticsEl2 = document.getElementById('pa-view-logistics');\r\n                            if (logisticsEl2) {\r\n                                logisticsEl2.innerHTML = '<div style=\"padding:20px; text-align:center; color:#888;\">Syncing live prep…</div>';\r\n                            }\r\n                            if (typeof window.evalOperationButtons === 'function') window.evalOperationButtons();\r\n                            return;\r\n                        }\r\n                        if (typeof window.evalOperationButtons === 'function') window.evalOperationButtons();\r\n                    } catch (eLive1) { /* ignore */ }\r\n                    if (!( !localEmpty && window.paLoadedForProject !== projectId && remoteHas )) return;\r\n                    // Wrong-project + Sheets has rows: fall through to full hydrate path below\r\n                }\r\n            }\r\n            // Prep live: if state-doc fixtures already have overrideDept, do not replace with\r\n            // a collection/Sheets snapshot that still lacks it (common right after refresh).\r\n            var incoming = res.current || [];\r\n            if (window.dalPrepUiOpen && window.dalPaLiveSyncMode === 'fi