  // Strip sublist (formula) and location to consolidate across the entire project by Department\r\n        let compKey = cName + \"|||\" + deptUid;\r\n        if(!deptCables.has(compKey)) deptCables.set(compKey, { cName: cName, deptUid: deptUid, formula: 'Standalone', location: 'General', cables: [] }); \r\n        deptCables.get(compKey).cables.push(pa); \r\n    });\r\n\r\n    // Setup base case asset\r\n    let caseAsset = globalAssets.find(a => (a.nestingLevel == 3 || a.nestingLevel == 4 || a.type === 'Container') && (a.name.toUpperCase().includes('CBL') || a.name.toUpperCase().includes('CABLE')));\r\n    if (!caseAsset) caseAsset = globalAssets.find(a => (a.nestingLevel == 3 || a.nestingLevel == 4 || a.type === 'Container') && (a.name.toUpperCase().includes('CASE') || a.name.toUpperCase().includes('TRUNK')));\r\n    if (!caseAsset) caseAsset = globalAssets.find(a => a.nestingLevel == 3 || a.type === 'Container');\r\n    \r\n    if (!caseAsset) return alert(\"No generic case found in Vault.\");\r\n\r\n    let actionsTaken = false;\r\n    let cap = parseInt(caseAsset.capacity, 10) || 50;\r\n    if (isNaN(cap) || cap <= 0) cap = 50;\r\n\r\n    // 2. Cleanup all old generic auto cases\r\n    for (let i = currentProjectAssets.length - 1; i >= 0; i--) {\r\n        let pa = currentProjectAssets[i];\r\n        if (pa.isGenericAuto) {\r\n            currentProjectAssets.splice(i, 1);\r\n        }\r\n    }\r\n\r\n    // 3. Pack items by Segregated Tag Group\r\n    if (deptCables.size > 0) { \r\n        deptCables.forEach((info, compKey) => {\r\n            let cables = info.cables;\r\n            let dObj = typeof getDeptObj === 'function' ? getDeptObj(info.deptUid) : { name: 'Unassigned' };\r\n            let trunkForm = \"[BULK] \" + info.cName.toUpperCase() + \" CASE - \" + dObj.name.toUpperCase();\r\n            \r\n            let currentCid = caseAsset.id + \"|||\" + trunkForm;\r\n            let totalCablesQty = 0;\r\n\r\n            cables.forEach(cPa => {\r\n                totalCablesQty += parseInt(cPa.qty, 10) || 1;\r\n                cPa.containerUid = currentCid;\r\n                cPa.isExplicitlyUnpacked = false;\r\n                actionsTaken = true;\r\n            }); \r\n            \r\n            let neededTrunks = Math.ceil(totalCablesQty / cap);\r\n            if (neededTrunks === 0) neededTrunks = 1;\r\n            \r\n            for (let i = 0; i < neededTrunks; i++) {\r\n                currentProjectAssets.push({ \r\n                    assetId: caseAsset.id, \r\n                    qty: 1, \r\n                    formula: trunkForm, \r\n                    location: info.location, \r\n                    creator: myName, \r\n                    overrideDept: info.deptUid,\r\n                    isAuto: true,\r\n                    isGenericAuto: true\r\n                });\r\n            }\r\n        }); \r\n    }\r\n\r\n    if (actionsTaken) { \r\n        if (typeof renderProjectAssetsUI === 'function') renderProjectAssetsUI(); \r\n    } else {\r\n        alert(\"No matching loose bulk items found, or they are already perfectly packed.\");\r\n    }\r\n};\r\n\r\n// ==========================================\r\n// --- AUTONOMOUS PACKING DETECTION ENGINE ---\r\n// ==========================================\r\n// @INDEX: PA_LOGIC -> Autonomous Packing Detection Engine\r\nwindow.evaluatePackingReadiness = function(saveToDb = false) {\r\n    if (!window.currentReadinessState) window.currentReadinessState = {};\r\n    \r\n    let needsPacking = false;\r\n    let hasAutoContainers = false;\r\n    let packableItemFound = false;\r\n    let calculatedConsumablesExpense = 0;\r\n    \r\n    if (typeof currentProjectAssets === 'undefined' || currentProjectAssets.length === 0) return;\r\n    \r\n    currentProjectAssets.forEach(pa => {\r\n        if (pa.isShortage) return;\r\n        let asset = globalAssets.find(a => a.id === pa.assetId);\r\n        if (!asset) return;\r\n        \r\n        let isContainer = (asset.nestingLevel == 3 || asset.nestingLevel == 4 || asset.nestingLevel == 5 || asset.type === 'Container');\r\n        let parent = typeof getParentCaseForAsset === 'function' ? getParentCaseForAsset(asset.name) : null;\r\n        let hasInherentContainer = !!parent;\r\n        \r\n        if (asset.isConsumable) {\r\n            let usageFrac = parseFloat(pa.qty) || 0;\r\n            let price = parseFloat(asset.price) || 0;\r\n            calculatedConsumablesExpense += (usageFrac * price);\r\n        }\r\n        \r\n        // The Matryoshka Rule: Only loose items without inherent cases need manual packing\r\n        if (!isContainer && !hasInherentContainer) {\r\n            packableItemFound = true;\r\n            if (!pa.containerUid) {\r\n                needsPacking = true; // Found a loose item waiting for a miracle!\r\n            }\r\n        }\r\n        \r\n        if (pa.isAuto) hasAutoContainers = true;\r\n    });\r\n    \r\n    let allVisibleDepts = Array.from(document.querySelectorAll('.eq-dept-finished-cb')).map(cb => cb.dataset.dept);\r\n    let allChecked = allVisibleDepts.length > 0 && allVisibleDepts.every(d => window.currentReadinessState.eq_depts && window.currentReadinessState.eq_depts.includes(d));\r\n    \r\n    let baseState = allChecked ? 'finished' : 'draft';\r\n    \r\n    // Only upgrade to Packed if there were actually loose items, and ALL of them have been securely put into cases\r\n    if (packableItemFound && !needsPacking) {\r\n        baseState = hasAutoContainers ? 'packed_auto' : 'packed_human';\r\n    }\r\n    \r\n    if (window.currentReadinessState.eq !== baseState || window.currentReadinessState.consumablesExpense !== calculatedConsumablesExpense) {\r\n        window.currentReadinessState.eq = baseState;\r\n        window.currentReadinessState.consumablesExpense = calculatedConsumablesExpense;\r\n        \r\n        if (saveToDb && typeof updateEqReadinessToDatabase === 'function') {\r\n            updateEqReadinessToDatabase();\r\n        }\r\n    }\r\n};\r\n\n\n\r\n/**\r\n * 02e5_Logic_Sync.html\r\n * Domain: Network saving, delta calculations, and shortage resolution.\r\n */\r\n\r\n// @INDEX: PA_LOGIC -> Shortage Queue Processing\r\nfunction processShortageQueue(parentLoc) {\r\n    if (!window.pendingShortages || window.pendingShortages.length === 0) return;\r\n    \r\n    let html = window.pendingShortages.map(s => `<li style=\"padding:4px 0; border-bottom:1px solid #333;\"><b style=\"color:#ef4444;\">${s.shortQty}x</b> ${s.asset.name}</li>`).join('');\r\n    document.getElementById('shortage-item-list').innerHTML = `<ul style=\"margin:0; padding:0; list-style:none;\">${html}</ul>`;\r\n    \r\n    let subrentLocs = new Set();\r\n    currentProjectAssets.forEach(pa => {\r\n        if (pa.isShortage && pa.location) {\r\n            subrentLocs.add(pa.location);\r\n        }\r\n    });\r\n    \r\n    let sel = document.getElementById('shortage-vendor-select');\r\n    let selHtml = '<option value=\"SHORTAGE LIST\">General Shortage List</option>';\r\n    subrentLocs.forEach(loc => {\r\n        if (loc.toUpperCase() !== \"SHORTAGE LIST\") {\r\n            selHtml += `<option value=\"${loc}\">${loc}</option>`;\r\n        }\r\n    });\r\n    selHtml += '<option value=\"NEW\">+ Specific Subrent Vendor...</option>';\r\n    sel.innerHTML = selHtml;\r\n    \r\n    document.getElementById('shortage-new-vendor-input').style.display = 'none';\r\n    document.getElementById('shortage-new-vendor-input').value = '';\r\n    window.shortageParentLoc = parentLoc || \"General\";\r\n    \r\n    document.getElementById('shortage-modal-overlay').style.display = 'flex';\r\n}\r\n\r\nfunction toggleShortageNewVendor() {\r\n    let sel = document.getElementById('shortage-vendor-select');\r\n    let inp = document.getElementById('shortage-new-vendor-input');\r\n    inp.style.display = (sel.value === 'NEW') ? 'block' : 'none';\r\n    if (sel.value === 'NEW') inp.focus();\r\n}\r\n\r\nfunction cancelShortages() {\r\n    window.pendingShortages = [];\r\n    document.getElementById('shortage-modal-overlay').style.display = 'none';\r\n}\r\n\r\nfunction confirmShortages() {\r\n    let sel = document.getElementById('shortage-vendor-select').value;\r\n    let newVendor = document.getElementById('shortage-new-vendor-input').value.trim();\r\n    let loc = \"\";\r\n    \r\n    if (sel === 'NEW') {\r\n        if (!newVendor) return alert(\"Please enter a vendor name.\");\r\n        loc = newVendor.toUpperCase();\r\n    } else if (sel) {\r\n        loc = sel;\r\n    } else {\r\n        return alert(\"Please select a vendor.\");\r\n    }\r\n    \r\n    try {\r\n        window.pendingShortages.forEach(s => {\r\n            let targetFormula = s.formula === \"Standalone\" ? \"TEMPORARY_SHORT_\" + Date.now() + Math.random() : \"TEMPORARY_\" + Date.now() + Math.random();\r\n            let existing = currentProjectAssets.find(pa => pa.assetId === s.asset.id && pa.location === loc && pa.formula === targetFormula);\r\n            if (existing) {\r\n                existing.qty = parseInt(existing.qty, 10) + s.shortQty;\r\n                existing.isShortage = true;\r\n            } else {\r\n                window.insertIntoProjectAssets({\r\n                            assetId: s.asset.id,\r\n                    qty: s.shortQty,\r\n                    formula: targetFormula,\r\n                    location: loc,\r\n                    isShortage: true,\r\n                    creator: typeof ACTIVE_USER_NAME !== 'undefined' ? ACTIVE_USER_NAME : 'System'\r\n                });\r\n            }\r\n        });\r\n        \r\n        let tempFormulas = [...new Set(currentProjectAssets.filter(pa => pa.location === loc && pa.formula.startsWith(\"TEMPORARY_\")).map(pa => pa.formula))];\r\n        tempFormulas.forEach(tForm => {\r\n            if (typeof window.syncFormulaToItems === 'function') window.syncFormulaToItems(loc, tForm);\r\n        });\r\n        \r\n    } catch (err) { console.error(\"